11	func preClaimIntakeFindingFingerprint(candidate *bead.Bead, ruleID, reason, decisionSource, policyMode, decision, suggestedAction string) string {
12		promptFingerprint := ""
13		if candidate != nil {
14			promptFingerprint = bead.PromptFingerprint(*candidate)
15		}
16		baseFingerprint := readinessDecisionFingerprint(ruleID, reason, decisionSource, policyMode, decision, suggestedAction)
17		if baseFingerprint == "" && promptFingerprint == "" {
18			return ""
19		}
20		return hashText(baseFingerprint + "\x00" + promptFingerprint)
21	}
