23	func preClaimIntakeOverrideHonored(store ExecuteBeadLoopStore, candidate *bead.Bead, findingFingerprint string) (bool, error) {
24		if store == nil || candidate == nil {
25			return false, nil
26		}
27		findingFingerprint = strings.TrimSpace(findingFingerprint)
28		if findingFingerprint == "" {
29			return false, nil
30		}
31		events, err := store.Events(candidate.ID)
32		if err != nil {
33			return false, err
34		}
35		promptFingerprint := bead.PromptFingerprint(*candidate)
36		latestTriaged := -1
37		latestBlocked := -1
38		for i, ev := range events {
39			fields := eventBodyFields(ev.Body)
40			switch ev.Kind {
41			case "triaged":
42				if strings.TrimSpace(fields["accepted_fingerprint"]) == findingFingerprint &&
43					strings.TrimSpace(fields["accepted_prompt_fingerprint"]) == promptFingerprint {
44					latestTriaged = i
45				}
46			case "intake.blocked", "pre_claim_intake.blocked":
47				if strings.TrimSpace(fields["fingerprint"]) == findingFingerprint {
48					latestBlocked = i
49				}
50			}
51		}
52		return latestTriaged >= 0 && latestTriaged > latestBlocked, nil
53	}
54	
55	func eventBodyFields(body string) map[string]string {
56		fields := map[string]string{}
57		if strings.TrimSpace(body) == "" {
58			return fields
59		}
60		var raw map[string]any
61		if err := json.Unmarshal([]byte(body), &raw); err != nil {
62			return fields
63		}
64		for k, v := range raw {
65			if s, ok := v.(string); ok {
66				fields[k] = s
67			}
68		}
69		return fields
70	}
