func isDuplicateIntakeBlockedEntry(store ExecuteBeadLoopStore, beadID, ruleFingerprint string) bool {
	if store == nil || beadID == "" || ruleFingerprint == "" {
		return false
	}
	events, err := store.Events(beadID)
	if err != nil {
		return false
	}
	for _, ev := range events {
		if ev.Kind == "intake.blocked" {
			fields := eventBodyFields(ev.Body)
			if strings.TrimSpace(fields["rule_fingerprint"]) == ruleFingerprint {
				return true
			}
		}
	}
	return false
}

