func extractIntakeBlockedEntries(eventsJSON any) []map[string]any {
	var entries []map[string]any
	if eventsJSON == nil {
		return entries
	}
	eventsStr, ok := eventsJSON.(string)
	if !ok {
		return entries
	}
	if strings.TrimSpace(eventsStr) == "" {
		return entries
	}
	var events []map[string]any
	if err := json.Unmarshal([]byte(eventsStr), &events); err != nil {
		return entries
	}
	for _, ev := range events {
		if kind, ok := ev["kind"].(string); ok && kind == "intake.blocked" {
			if body, ok := ev["body"].(string); ok {
				var bodyObj map[string]any
				if err := json.Unmarshal([]byte(body), &bodyObj); err == nil {
					entries = append(entries, bodyObj)
				}
			}
		}
	}
	return entries
}

